const items = $input.all();
function firstString(...values) {
  for (const value of values) {
    if (value === null || value === undefined) continue;
    const text = String(value).trim();
    if (text) return text;
  }
  return '';
}
function boolValue(value) {
  if (value === true || value === false) return value;
  const text = String(value ?? '').trim().toLowerCase();
  return ['true', 'yes', '1'].includes(text);
}
function parseOutput(output) {
  if (output && typeof output === 'object') {
    return { verdict: firstString(output.verdict).toUpperCase(), reason: firstString(output.reason), memory_used: boolValue(output.memory_used), parsed: output, raw: JSON.stringify(output) };
  }
  const text = String(output ?? '').trim();
  const cleaned = text.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
  for (const candidate of [cleaned, cleaned.match(/\{[\s\S]*\}/)?.[0]]) {
    if (!candidate) continue;
    try {
      const obj = JSON.parse(candidate);
      return { verdict: firstString(obj?.verdict).toUpperCase(), reason: firstString(obj?.reason), memory_used: boolValue(obj?.memory_used), parsed: obj, raw: text };
    } catch {}
  }
  const lineMatch = cleaned.match(/\b(NOT_SPAM|SPAM)\b\s*(?:\||:|-)?\s*([\s\S]*)$/i);
  const verdict = lineMatch ? lineMatch[1].toUpperCase() : '';
  return { verdict, reason: firstString(lineMatch?.[2], cleaned.slice(0, 240)), memory_used: /qdrant|memory/i.test(cleaned), parsed: null, raw: text };
}
return items.map((item) => {
  const source = item.json ?? {};
  const parsed = parseOutput(source.output);
  const routeMailbox = firstString(source.routeMailbox, source.account_id);
  const imapUid = firstString(source.imapUid, source.uid, source.attributes?.uid);
  const sourceFrom = firstString(source.sourceFrom, source.From, source.from);
  const sourceSubject = firstString(source.sourceSubject, source.Subject, source.subject, '(no subject)');
  const sourceSnippet = firstString(source.sourceSnippet, source.snippet, source.textPlain, source.textHtml);
  const sourceMessageId = firstString(source.sourceMessageId, source.rfcMessageId, source.messageId, imapUid, source.id);
  const validationOk = Boolean(routeMailbox && imapUid && sourceFrom && (parsed.verdict === 'SPAM' || parsed.verdict === 'NOT_SPAM'));
